function formatDate(iso) {
  if (!iso) return "";
  return iso.split("T")[0];
}

function resolveResponsavel(assignments) {
  if (!assignments) return "Equipe";
  const ids = Object.keys(assignments);
  if (!ids.length) return "Equipe";
  for (const id of ids) {
    if (USER_MAP[id]) return USER_MAP[id];
  }
  return "Equipe";
}

function resolveAreaCliente(appliedCategories, categoryDescriptions) {
  if (!appliedCategories || !categoryDescriptions) return "Todas as áreas";
  const labels = Object.entries(appliedCategories)
    .filter(([, v]) => v === true)
    .map(([k]) => categoryDescriptions[k])
    .filter(Boolean);
  return labels.length > 0 ? labels[0] : "Todas as áreas";
}

function resolveStatus(bucketId, percentComplete, dueDateTime) {
  const bucketStatus = BUCKET_STATUS[bucketId] || "Backlog";

  // Bloqueado, Validação e Concluído têm prioridade
  if (bucketStatus === "Bloqueado")  return "Bloqueado";
  if (bucketStatus === "Validação")  return "Validação";
  if (bucketStatus === "Concluído" || percentComplete === 100) return "Concluído";

  // Atraso: dueDate venceu e tarefa não está em nenhum dos estados acima
  // Aplica para Em andamento e Planejada (Backlog não conta como atrasado)
  if (dueDateTime && bucketStatus !== "Backlog") {
    const due = new Date(dueDateTime);
    const today = new Date(); today.setHours(0,0,0,0);
    if (due < today) return "Atrasado";
  }

  return bucketStatus;
}

