function compileTasksText(taskList) {
  if (taskList.length === 0) return "Nenhuma demanda registrada nesta categoria.";
  return taskList.map(t => {
    let text = `- Demanda: "${t.atividade}" (Pilar: ${t.pilar} | Área Cliente: ${t.areaCliente})\n`;
    if (t.description) text += `  Anotações: ${t.description.trim()}\n`;
    const checklist = t.checklist || {};
    const checklistKeys = Object.keys(checklist);
    if (checklistKeys.length > 0) {
      text += `  Checklist:\n`;
      checklistKeys.forEach(k => {
        const item = checklist[k];
        text += `    - [${item.isChecked ? "x" : " "}] ${item.title}\n`;
      });
    }
    return text;
  }).join("\n");
}

